import { Injectable, signal, computed } from '@angular/core';
import { HttpClient } from '@angular/common/http';
import { Router } from '@angular/router';
import { tap } from 'rxjs/operators';
import { Observable, of } from 'rxjs';
import { environment } from '../../../environments/environment';
import { AdminUser } from '../models';

const TOKEN_KEY = 'auth_token';
const USER_KEY = 'user';

function readStoredUser(): AdminUser | null {
  try {
    const raw = localStorage.getItem(USER_KEY);
    return raw ? (JSON.parse(raw) as AdminUser) : null;
  } catch {
    return null;
  }
}

@Injectable({ providedIn: 'root' })
export class AuthService {
  private readonly apiUrl = environment.apiUrl;
  private _token = signal<string | null>(localStorage.getItem(TOKEN_KEY));
  private _user = signal<AdminUser | null>(readStoredUser());

  readonly isLoggedIn = computed(() => !!this._token());
  readonly token = this._token.asReadonly();
  readonly user = this._user.asReadonly();

  constructor(
    private http: HttpClient,
    private router: Router,
  ) {}

  login(email: string, password: string): Observable<{ user: AdminUser; token: string }> {
    return this.http
      .post<{ user: AdminUser; token: string }>(`${this.apiUrl}/admin/login`, { email, password })
      .pipe(tap((response) => this.persist(response.token, response.user)));
  }

  /**
   * Demo Mode bypass — lets reviewers (and the screenshot capture system) reach the full
   * authenticated admin UI without a live backend. Seeds mock admin credentials and navigates
   * straight to the admin dashboard.
   */
  demoLogin(): Observable<void> {
    const user: AdminUser = {
      id: 'demo-admin',
      email: 'admin@newswire.local',
      name: 'Demo Admin',
    };
    this.persist('demo-token', user);
    this.router.navigate(['/admin']);
    return of(void 0);
  }

  logout(): void {
    localStorage.removeItem(TOKEN_KEY);
    localStorage.removeItem(USER_KEY);
    localStorage.removeItem('access_token');
    localStorage.removeItem('isAuthenticated');
    this._token.set(null);
    this._user.set(null);
    this.router.navigate(['/admin/login']);
  }

  private persist(token: string, user: AdminUser): void {
    localStorage.setItem(TOKEN_KEY, token);
    localStorage.setItem('access_token', token);
    localStorage.setItem('isAuthenticated', 'true');
    localStorage.setItem(USER_KEY, JSON.stringify(user));
    this._token.set(token);
    this._user.set(user);
  }
}
